import React from 'react';
import CadastroCliente from './components/CadastroCliente';

function App() {
  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem' }}>
      <h1 style={{ textAlign: 'center', color: '#153a6b' }}>DOC PROVEDOR</h1>
      <CadastroCliente />
    </div>
  );
}

export default App;
